}

using sv_29547b3ceb8f45e3bcc775658789c305.Models;

namespace sv_29547b3ceb8f45e3bcc775658789c305.Services;

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with tomato, mozzarella, and basil.", 30),
            new(2, "Pasta Carbonara", "Roman pasta dish with eggs, pecorino, guanciale, and black pepper.", 25),
            new(3, "Risotto alla Milanese", "Creamy saffron-infused risotto from Milan.", 45),
        },
        [2] = new List<Recipe>
        {
            new(4, "Chicken Tikka Masala", "Roasted chicken chunks in a spiced creamy tomato sauce.", 50),
            new(5, "Palak Paneer", "Fresh spinach cooked with paneer cubes and aromatic spices.", 35),
            new(6, "Biryani", "Fragrant basmati rice layered with spiced meat and caramelized onions.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Spit-grilled pork tacos with pineapple, onion, and cilantro.", 40),
            new(8, "Guacamole", "Fresh avocado dip with lime, cilantro, and jalapeño.", 10),
            new(9, "Enchiladas Verdes", "Corn tortillas filled with chicken and topped with green salsa.", 45),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        return SeedData.TryGetValue(cuisineId, out var recipes)
            ? recipes
            : new List<Recipe>();
    }
}

